#include <iostream>
#include <fstream>
#include <string>
#include "ap_axi_sdata.h"
#include "hls_stream.h"
#include "common/xf_common.hpp"
#include "common/xf_infra.hpp"

// Forward declaration of the top-level HLS function
void image_passthrough(
    hls::stream<ap_axiu<128, 0, 0, 0>>& stream_in,
    hls::stream<ap_axiu<32, 0, 0, 0>>& stream_out);

int main() {
    int rows = 460;
    int cols = 640;
    int total_pixels = rows * cols;
    int beats = total_pixels / 4; // 4 pixels processed per clock beat

    // Open the input file generated by the Python script
    std::ifstream infile("input_bits.txt");
    if (!infile.is_open()) {
        std::cerr << "Error: Could not open input_bits.txt" << std::endl;
        return -1;
    }

    // AXI streams for input and output
    hls::stream<ap_axiu<128, 0, 0, 0>> stream_in("stream_in");
    hls::stream<ap_axiu<32, 0, 0, 0>> stream_out("stream_out");

    std::cout << "Reading input_bits.txt and converting to AXI stream..." << std::endl;

    // 1. Read the input text file and pack 16 bytes (128 bits) per beat
    for (int i = 0; i < beats; i++) {
        ap_axiu<128, 0, 0, 0> in_word;
        in_word.data = 0;
        in_word.keep = -1; // All bytes are valid
        in_word.strb = -1;
        in_word.user = (i == 0) ? 1 : 0;          // Start of Frame
        in_word.last = (i == beats - 1) ? 1 : 0;  // End of Line/Frame

        // Read 16 bytes (4 RGBA pixels) to pack into a 128-bit word
        for (int byte_idx = 0; byte_idx < 16; byte_idx++) {
            char bit_chars[9];
            bit_chars[8] = '\0';

            // Read 8 characters ('0' or '1') representing a single byte
            infile.read(bit_chars, 8);
            if (infile.eof()) {
                break;
            }

            // Convert binary string to uint8_t
            uint8_t byte_val = 0;
            for (int b = 0; b < 8; b++) {
                if (bit_chars[b] == '1') {
                    byte_val |= (1 << (7 - b));
                }
            }

            // Pack the byte into the 128-bit word
            in_word.data |= ((ap_uint<128>)byte_val) << (byte_idx * 8);
        }
        stream_in.write(in_word);
    }
    infile.close();

    std::cout << "Running Vitis HLS module..." << std::endl;

    // 2. Call the HLS module
    image_passthrough(stream_in, stream_out);

    std::cout << "Module execution complete. Extracting output to raw bits..." << std::endl;

    // 3. Write the output as raw ASCII '0' and '1' bits
    std::ofstream outfile("/misc/scratch/sp02-senior-design/augmented-reality-glasses/fpga_software/PL_temp/output_bits.txt");
    if (!outfile.is_open()) {
        std::cerr << "Error: Could not open output_bits.txt for writing." << std::endl;
        return -1;
    }

    for (int i = 0; i < beats; i++) {
        ap_axiu<32, 0, 0, 0> out_word = stream_out.read();

        // Each 32-bit word contains 4 grayscale pixels (8 bits each)
        for (int p = 0; p < 4; p++) {
            // Extract the 8-bit pixel
            uint8_t pixel = (out_word.data >> (p * 8)) & 0xFF;

            // Convert pixel to an 8-character binary string and write
            for (int b = 7; b >= 0; b--) {
                if ((pixel >> b) & 1) {
                    outfile << "1";
                } else {
                    outfile << "0";
                }
            }
        }
    }
    outfile.close();

    std::cout << "Testbench completed successfully. Output saved to output_bits.txt" << std::endl;

    return 0;
}
